using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities to the research agent.
/// Uses a search API to find relevant information on the web.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;
    private readonly ILogger<WebSearchTool> _logger;

    public WebSearchTool(HttpClient httpClient, ILogger<WebSearchTool> logger)
    {
        _httpClient = httpClient;
        _logger = logger;
    }

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        if (string.IsNullOrWhiteSpace(query))
        {
            return "Error: Search query cannot be empty.";
        }

        maxResults = Math.Clamp(maxResults, 1, 10);

        _logger.LogInformation("Searching web for: {Query} (max {MaxResults} results)", query, maxResults);

        try
        {
            // Use a web search API (configurable via environment variable)
            var searchApiBase = Environment.GetEnvironmentVariable("SEARCH_API_BASE")
                ?? "https://api.search.example.com";
            var searchApiKey = Environment.GetEnvironmentVariable("SEARCH_API_KEY") ?? "";

            var request = new HttpRequestMessage(HttpMethod.Get,
                $"{searchApiBase}/search?q={Uri.EscapeDataString(query)}&count={maxResults}");

            if (!string.IsNullOrEmpty(searchApiKey))
            {
                request.Headers.Add("Authorization", $"Bearer {searchApiKey}");
            }

            var response = await _httpClient.SendAsync(request, cancellationToken);

            if (!response.IsSuccessStatusCode)
            {
                _logger.LogWarning("Search API returned {StatusCode}, falling back to simulated results", response.StatusCode);
                return GetSimulatedResults(query, maxResults);
            }

            var content = await response.Content.ReadAsStringAsync(cancellationToken);
            return content;
        }
        catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
        {
            _logger.LogWarning(ex, "Search API unavailable, using simulated results");
            return GetSimulatedResults(query, maxResults);
        }
    }

    private static string GetSimulatedResults(string query, int maxResults)
    {
        // Provide simulated results when no search API is configured.
        // In production, replace with a real search provider (Bing, Google, Brave, etc.)
        var results = new List<object>();
        for (int i = 1; i <= maxResults; i++)
        {
            results.Add(new
            {
                position = i,
                title = $"Result {i} for '{query}'",
                snippet = $"This is a simulated search result about '{query}'. " +
                          $"In production, configure SEARCH_API_BASE and SEARCH_API_KEY " +
                          $"environment variables to use a real search provider.",
                url = $"https://example.com/result-{i}?q={Uri.EscapeDataString(query)}"
            });
        }

        return JsonSerializer.Serialize(new { query, results }, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.Logging;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize findings.
/// Notes are stored in memory for the duration of the research session.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];
    private readonly ILogger<NoteTakingTool> _logger;

    public NoteTakingTool(ILogger<NoteTakingTool> logger)
    {
        _logger = logger;
    }

    [Description("Saves a research note with a title and content. Use this to record important findings during research.")]
    public string AddNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content/body of the note with research findings")] string content,
        [Description("Optional source URL where this information was found")] string? sourceUrl = null)
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(content))
        {
            return "Error: Both title and content are required.";
        }

        var note = new ResearchNote
        {
            Id = _notes.Count + 1,
            Title = title.Trim(),
            Content = content.Trim(),
            SourceUrl = sourceUrl?.Trim(),
            CreatedAt = DateTimeOffset.UtcNow
        };

        _notes.Add(note);
        _logger.LogInformation("Note added: #{Id} - {Title}", note.Id, note.Title);

        return $"Note #{note.Id} saved successfully: '{note.Title}'";
    }

    [Description("Retrieves all saved research notes. Returns all notes with their titles, content, and sources.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        sb.AppendLine();

        foreach (var note in _notes)
        {
            sb.AppendLine($"--- Note #{note.Id}: {note.Title} ---");
            sb.AppendLine(note.Content);
            if (!string.IsNullOrEmpty(note.SourceUrl))
            {
                sb.AppendLine($"Source: {note.SourceUrl}");
            }
            sb.AppendLine();
        }

        return sb.ToString();
    }

    [Description("Searches through saved notes for a specific keyword or phrase.")]
    public string SearchNotes(
        [Description("The keyword or phrase to search for in notes")] string keyword)
    {
        if (string.IsNullOrWhiteSpace(keyword))
        {
            return "Error: Search keyword cannot be empty.";
        }

        var matches = _notes
            .Where(n => n.Title.Contains(keyword, StringComparison.OrdinalIgnoreCase)
                     || n.Content.Contains(keyword, StringComparison.OrdinalIgnoreCase))
            .ToList();

        if (matches.Count == 0)
        {
            return $"No notes found matching '{keyword}'.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Found {matches.Count} note(s) matching '{keyword}':");
        sb.AppendLine();

        foreach (var note in matches)
        {
            sb.AppendLine($"- Note #{note.Id}: {note.Title}");
            sb.AppendLine($"  {note.Content[..Math.Min(note.Content.Length, 150)]}...");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private sealed class ResearchNote
    {
        public required int Id { get; init; }
        public required string Title { get; init; }
        public required string Content { get; init; }
        public string? SourceUrl { get; init; }
        public DateTimeOffset CreatedAt { get; init; }
    }
}

