using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.Logging;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize findings.
/// Notes are stored in memory for the duration of the research session.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];
    private readonly ILogger<NoteTakingTool> _logger;

    public NoteTakingTool(ILogger<NoteTakingTool> logger)
    {
        _logger = logger;
    }

    [Description("Saves a research note with a title and content. Use this to record important findings during research.")]
    public string AddNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content/body of the note with research findings")] string content,
        [Description("Optional source URL where this information was found")] string? sourceUrl = null)
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(content))
        {
            return "Error: Both title and content are required.";
        }

        var note = new ResearchNote
        {
            Id = _notes.Count + 1,
            Title = title.Trim(),
            Content = content.Trim(),
            SourceUrl = sourceUrl?.Trim(),
            CreatedAt = DateTimeOffset.UtcNow
        };

        _notes.Add(note);
        _logger.LogInformation("Note added: #{Id} - {Title}", note.Id, note.Title);

        return $"Note #{note.Id} saved successfully: '{note.Title}'";
    }

    [Description("Retrieves all saved research notes. Returns all notes with their titles, content, and sources.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        sb.AppendLine();

        foreach (var note in _notes)
        {
            sb.AppendLine($"--- Note #{note.Id}: {note.Title} ---");
            sb.AppendLine(note.Content);
            if (!string.IsNullOrEmpty(note.SourceUrl))
            {
                sb.AppendLine($"Source: {note.SourceUrl}");
            }
            sb.AppendLine();
        }

        return sb.ToString();
    }

    [Description("Searches through saved notes for a specific keyword or phrase.")]
    public string SearchNotes(
        [Description("The keyword or phrase to search for in notes")] string keyword)
    {
        if (string.IsNullOrWhiteSpace(keyword))
        {
            return "Error: Search keyword cannot be empty.";
        }

        var matches = _notes
            .Where(n => n.Title.Contains(keyword, StringComparison.OrdinalIgnoreCase)
                     || n.Content.Contains(keyword, StringComparison.OrdinalIgnoreCase))
            .ToList();

        if (matches.Count == 0)
        {
            return $"No notes found matching '{keyword}'.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Found {matches.Count} note(s) matching '{keyword}':");
        sb.AppendLine();

        foreach (var note in matches)
        {
            sb.AppendLine($"- Note #{note.Id}: {note.Title}");
            sb.AppendLine($"  {note.Content[..Math.Min(note.Content.Length, 150)]}...");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private sealed class ResearchNote
    {
        public required int Id { get; init; }
        public required string Title { get; init; }
        public required string Content { get; init; }
        public string? SourceUrl { get; init; }
        public DateTimeOffset CreatedAt { get; init; }
    }
}

