using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// Configure logging
builder.Logging.SetMinimumLevel(LogLevel.Information);
builder.Logging.AddConsole();

// Register HttpClient for the search tool
builder.Services.AddHttpClient<WebSearchTool>();

// Register tool instances as singletons (stateful note-taking tool)
builder.Services.AddSingleton<NoteTakingTool>();

// Register the OpenAI-backed chat client via MEAI abstraction
builder.Services.AddChatClient(chatClientBuilder =>
{
    var apiKey = builder.Configuration["AI:ApiKey"]
        ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
        ?? throw new InvalidOperationException(
            "AI:ApiKey not configured. Set the OPENAI_API_KEY environment variable or configure AI:ApiKey in appsettings.json.");

    var modelId = builder.Configuration["AI:ModelId"]
        ?? Environment.GetEnvironmentVariable("OPENAI_MODEL")
        ?? "gpt-4o-mini-2024-07-18";

    return chatClientBuilder
        .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey));
});

var host = builder.Build();

// Resolve services
var chatClient = host.Services.GetRequiredService<IChatClient>();
var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();
var logger = loggerFactory.CreateLogger("ResearchAgent");
var serviceProvider = host.Services;

// Create tools from the tool class instances using AIFunctionFactory
var webSearchTool = host.Services.GetRequiredService<WebSearchTool>();
var noteTakingTool = host.Services.GetRequiredService<NoteTakingTool>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(noteTakingTool.AddNote),
    AIFunctionFactory.Create(noteTakingTool.GetAllNotes),
    AIFunctionFactory.Create(noteTakingTool.SearchNotes),
};

// Create the ChatClientAgent with tools and system instructions
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant agent. Your job is to thoroughly research a topic
        provided by the user by searching the web and organizing your findings.

        Follow this workflow:
        1. Break down the research topic into key questions or subtopics.
        2. Use the SearchWebAsync tool to search for information on each subtopic.
        3. Use the AddNote tool to save important findings as you go — include source URLs.
        4. After gathering enough information, use GetAllNotes to review your collected research.
        5. Provide a comprehensive summary of your findings, organized by subtopic.

        Be thorough but focused. Cite your sources. If search results are limited,
        note what additional research might be needed.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and organizing findings into notes.",
    tools: tools,
    loggerFactory: loggerFactory,
    services: serviceProvider);

// Get the research topic from the user
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF + MEAI)     ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'   ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic: ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    Console.WriteLine();
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine("Working...");
    Console.WriteLine();

    try
    {
        var runOptions = new ChatClientAgentRunOptions(new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
        });

        var response = await agent.RunAsync(
            $"Please research the following topic thoroughly and provide a summary: {topic}",
            session: null,
            options: runOptions);

        Console.WriteLine("═══ Research Summary ═══");
        Console.WriteLine();
        Console.WriteLine(response.Text);
        Console.WriteLine();
        Console.WriteLine($"[Tokens used: {response.Usage?.TotalTokenCount ?? 0}]");
    }
    catch (Exception ex)
    {
        logger.LogError(ex, "Research failed");
        Console.WriteLine($"Error: {ex.Message}");
    }

    Console.WriteLine();
}

